final:
module binary_counter(
    input wire clk,
    input wire rst_n,
    output reg [3:0] count_out
    );

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
    if (!rst_n)
        count_out <= 4'b0000;
    else
        count_out <= count_out + 1;
end

endmodule
